-- Migration 010: Fix equipment catalog
-- Adds unique index on (name, is_homebrew) and re-inserts all equipment items
-- safely using ON CONFLICT DO NOTHING

-- Step 1: Remove any duplicate non-homebrew items (keep one per name)
DELETE FROM loot_items
WHERE is_homebrew = false
  AND id NOT IN (
    SELECT MIN(id)
    FROM loot_items
    WHERE is_homebrew = false
    GROUP BY name
  );

-- Step 2: Add unique constraint so future inserts can use ON CONFLICT
ALTER TABLE loot_items
  DROP CONSTRAINT IF EXISTS loot_items_name_homebrew_key;
ALTER TABLE loot_items
  ADD CONSTRAINT loot_items_name_homebrew_key UNIQUE (name, is_homebrew);

-- Step 3: Re-insert all equipment items safely
INSERT INTO loot_items (name, type, rarity, requires_attunement, weight, cost_gp, description, properties, is_homebrew)
